import test from "node:test";
import assert from "node:assert/strict";
import { ResponseCache } from "../src/cache.mjs";

test("mixed-case multi-dimensional variants remain isolated", () => {
  const cache = new ResponseCache();
  cache.put(
    "/catalog",
    { "ACCEPT-LANGUAGE": "en", "x-tier": "free" },
    {
      headers: { vary: "Accept-Language, X-Tier" },
      body: "english-free",
    },
  );

  const crossed = cache.match("/catalog", {
    "Accept-Language": "es",
    "X-Tier": "free",
  });
  assert.strictEqual(crossed, undefined, "a different locale hit the entry");
});

test("wildcard metadata never occupies cache storage", () => {
  const cache = new ResponseCache();
  cache.put(
    "/session",
    { cookie: "sid=a" },
    { headers: { vary: "*" }, body: "account-a" },
  );
  assert.strictEqual(cache.size, 0, "wildcard response was retained");
});
